module shift_register_8bit(clk, reset, load, data_in, shift, data_out);
    input clk;
    input reset;
    input load;
    input [7:0] data_in;
    input shift;
    output reg [7:0] data_out;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            data_out <= 8'b00000000;
        else if (load)
            data_out <= data_in;
        else if (shift)
            data_out <= {1'b0, data_out[7:1]};
    end
endmodule
